"use client";

import { ChevronLeft, ChevronRight } from "lucide-react";
import type * as React from "react";
import { cn } from "@/lib/utils";

export interface PaginationProps {
  /** Current page (1-indexed). */
  page: number;
  /** Total number of pages. */
  totalPages: number;
  /**
   * Build the URL for a given page. When provided, each control renders
   * as a real `<a href>` — the SEO-friendly / no-JS-required path. Prefer
   * this over `onPageChange` for indexable content (jobs, listings, docs).
   */
  href?: (page: number) => string;
  /**
   * Client-side handler. Rendered as `<button>` when `href` is not given.
   * Use for in-app pages that don't need SEO indexing.
   */
  onPageChange?: (page: number) => void;
  /**
   * How many page-number siblings to render on each side of the current
   * page. Total buttons: 1 + siblings×2 + 1. Defaults to 1: renders
   * `1 … 4 [5] 6 … 42`.
   */
  siblingCount?: number;
  /** Disables every control while a page transition is in flight. */
  loading?: boolean;
  className?: string;
}

/**
 * Pagination: grouped bar of page numbers between prev/next arrows,
 * enclosed in one bordered pill. Accepts either `href` (SEO-friendly
 * `<a>` output) or `onPageChange` (client-side). Renders nothing when
 * there's only one page.
 */
export function Pagination({
  page,
  totalPages,
  href,
  onPageChange,
  siblingCount = 1,
  loading = false,
  className,
}: PaginationProps): React.ReactElement | null {
  if (totalPages <= 1) return null;

  const atFirst = page === 1;
  const atLast = page === totalPages;
  const items = getPageItems(page, totalPages, siblingCount);

  return (
    <nav
      data-slot="pagination"
      aria-label="Pagination"
      aria-busy={loading || undefined}
      className={cn(
        // One bordered pill containing every control. `overflow-hidden`
        // clips the inner cells to the rounded corners so they don't
        // need their own radius on the outer edges.
        "inline-flex items-stretch overflow-hidden rounded-[var(--radius-6)] border border-hairline text-body-13",
        loading && "opacity-70",
        className,
      )}
    >
      <PageCell
        page={page - 1}
        disabled={atFirst || loading}
        href={href}
        onPageChange={onPageChange}
        ariaLabel="Previous page"
        icon={<ChevronLeft className="size-3.5" />}
        divider="end"
      />
      {items.map((item, i) => {
        const isLast = i === items.length - 1;
        if (item === "ellipsis") {
          return (
            <span
              key={`ellipsis-${i}`}
              aria-hidden
              className={cn(
                // Matches PageCell dimensions (size-8) so the bar
                // stays a stable width.
                "inline-flex size-8 shrink-0 items-center justify-center text-ink-tertiary tabular-nums",
                !isLast && "border-e border-hairline",
              )}
              data-slot="pagination-ellipsis"
            >
              …
            </span>
          );
        }
        return (
          <PageCell
            key={item}
            page={item}
            current={item === page}
            disabled={loading}
            href={href}
            onPageChange={onPageChange}
            ariaLabel={`Page ${item}`}
            label={String(item)}
            divider="end"
          />
        );
      })}
      <PageCell
        page={page + 1}
        disabled={atLast || loading}
        href={href}
        onPageChange={onPageChange}
        ariaLabel="Next page"
        icon={<ChevronRight className="size-3.5" />}
      />
    </nav>
  );
}

/* --------------------------- internals --------------------------- */

interface PageCellProps {
  page: number;
  label?: string;
  icon?: React.ReactNode;
  ariaLabel: string;
  current?: boolean;
  disabled?: boolean;
  href?: (page: number) => string;
  onPageChange?: (page: number) => void;
  /** Adds a divider on the trailing edge (all cells except the last). */
  divider?: "end";
}

function PageCell({
  page,
  label,
  icon,
  ariaLabel,
  current,
  disabled,
  href,
  onPageChange,
  divider,
}: PageCellProps): React.ReactElement {
  const className = cn(
    // Every cell is a fixed 32×32 square so the bar has a stable width
    // regardless of how many digits a page number carries or how many
    // cells the current range renders. `tabular-nums` keeps single- and
    // double-digit numbers optically centered within the same slot.
    "inline-flex size-8 shrink-0 items-center justify-center text-body-13 tabular-nums transition-colors duration-[var(--duration-state)] ease-[var(--ease-standard)]",
    // Active page uses the same surface-2 lift menu / combobox items use
    // for their active row -- reads as "you are here" without the shouty
    // full-contrast fill that bg-primary would give.
    current
      ? "bg-surface-2 text-ink"
      : "text-ink-muted hover:bg-surface-1 hover:text-ink",
    disabled && "pointer-events-none text-ink-tertiary",
    divider === "end" && "border-e border-hairline",
  );
  const inner = icon ?? label;

  if (href && !disabled) {
    return (
      <a
        href={href(page)}
        aria-label={ariaLabel}
        aria-current={current ? "page" : undefined}
        className={className}
      >
        {inner}
      </a>
    );
  }
  return (
    <button
      type="button"
      onClick={() => !disabled && onPageChange?.(page)}
      disabled={disabled}
      aria-label={ariaLabel}
      aria-current={current ? "page" : undefined}
      className={className}
    >
      {inner}
    </button>
  );
}

/**
 * Build the render list. Always produces exactly `siblingCount * 2 + 5`
 * items when the range is long enough to need ellipses, so the total
 * cell count stays stable as `page` changes and the bar never resizes
 * mid-navigation. Near the start / end, the ellipsis-side widens to
 * absorb the slot the missing ellipsis would have taken.
 */
function getPageItems(
  page: number,
  totalPages: number,
  siblingCount: number,
): Array<number | "ellipsis"> {
  const totalRendered = siblingCount * 2 + 5;

  // Short ranges: everything fits without ellipsis.
  if (totalPages <= totalRendered) {
    return Array.from({ length: totalPages }, (_, i) => i + 1);
  }

  const items: Array<number | "ellipsis"> = [];

  // Near start: [1 .. 2·sib+3] … last  → same total slots.
  if (page <= siblingCount + 3) {
    for (let p = 1; p <= siblingCount * 2 + 3; p++) items.push(p);
    items.push("ellipsis");
    items.push(totalPages);
    return items;
  }

  // Near end: 1 … [last-(2·sib+2) .. last]
  if (page >= totalPages - siblingCount - 2) {
    items.push(1);
    items.push("ellipsis");
    for (let p = totalPages - siblingCount * 2 - 2; p <= totalPages; p++) {
      items.push(p);
    }
    return items;
  }

  // Middle: 1 … [current-sib .. current+sib] … last
  items.push(1);
  items.push("ellipsis");
  for (let p = page - siblingCount; p <= page + siblingCount; p++) items.push(p);
  items.push("ellipsis");
  items.push(totalPages);
  return items;
}
